171	// fetchProviderModelsLive performs the live discovery via the agent service.
172	// For ENDPOINT kinds it filters by provider name; for HARNESS kinds it filters
173	// by harness name. The returned baseURL is sanitized (credentials, query, and
174	// fragment stripped) for ts-net display safety; harness rows return "".
175	func fetchProviderModelsLive(ctx context.Context, workDir, name string, kind ProviderKind) (*ProviderModelsResult, error) {
176		svc, err := agent.NewServiceFromWorkDir(workDir)
177		if err != nil {
178			return nil, fmt.Errorf("agent service: %w", err)
179		}
180	
181		filter := agentlib.ModelFilter{}
182		switch kind {
183		case ProviderKindEndpoint:
184			filter.Provider = name
185		case ProviderKindHarness:
186			filter.Harness = name
187		default:
188			return nil, fmt.Errorf("invalid kind: %s", kind)
189		}
190	
191		models, err := svc.ListModels(ctx, filter)
192		if err != nil {
193			return nil, fmt.Errorf("list models: %w", err)
194		}
195	
196		baseURL := ""
197		if kind == ProviderKindEndpoint {
198			// Pick up the provider's base URL from ListProviders, fall back to
199			// the first model's recorded EndpointBaseURL when discovery returned
200			// it.
201			if providers, perr := svc.ListProviders(ctx); perr == nil {
202				for _, p := range providers {
203					if strings.EqualFold(p.Name, name) {
204						baseURL = sanitizeBaseURL(p.BaseURL)
205						break
206					}
207				}
208			}
209			if baseURL == "" {
210				for _, m := range models {
211					if m.EndpointBaseURL != "" {
212						baseURL = sanitizeBaseURL(m.EndpointBaseURL)
213						break
214					}
215				}
216			}
217		}
218	
219		entries := make([]*ProviderModelEntry, 0, len(models))
220		for _, m := range models {
221			entry := &ProviderModelEntry{
222				ID:        m.ID,
223				Available: m.Available,
224			}
225			if m.ContextLength > 0 {
226				cl := m.ContextLength
227				entry.ContextLength = &cl
228			}
229			entries = append(entries, entry)
230		}
231	
232		return &ProviderModelsResult{
233			Name:      name,
234			Kind:      kind,
235			Models:    entries,
236			BaseURL:   baseURL,
237			FetchedAt: time.Now().UTC().Format(time.RFC3339),
238			FromCache: false,
239		}, nil
240	}
241	
242	// sanitizeBaseURL returns a base URL safe to surface over a ts-net trusted
243	// channel: credentials, query string, and fragment are dropped, the scheme
244	// and host are preserved, and any path is kept verbatim. Inputs that fail to
245	// parse, or lack a host, return "" — never the original raw string — so a
246	// malformed config cannot leak credentials downstream.
247	func sanitizeBaseURL(raw string) string {
248		raw = strings.TrimSpace(raw)
249		if raw == "" {
250			return ""
251		}
252		u, err := url.Parse(raw)
253		if err != nil {
254			return ""
255		}
256		if u.Scheme == "" || u.Host == "" {
257			return ""
258		}
259		clean := &url.URL{
260			Scheme: u.Scheme,
261			Host:   u.Host,
262			Path:   u.Path,
263		}
264		return clean.String()
265	}
